headers = {
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36",
    "Referer": "https://www.faultlineflyers.com/the-joy-of-soaring",
}

saved = []
for i, url in enumerate(URLS):
    fetch = url.replace("=w16383", "=w1200")
    dest = OUT / f"photo-{i + 1:02d}.jpg"
    req = urllib.request.Request(fetch, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=45) as resp:
            data = resp.read()
            if len(data) < 2000:
                continue
            dest.write_bytes(data)
            saved.append(dest.name)
            print(dest.name, len(data) // 1024, "KB")
    except Exception as e:
        print("fail", i + 1, e)

# also copy hero as extra if needed
hero = ROOT / "public" / "images" / "hero-grob-field.jpg"
if hero.exists() and len(saved) < 6:
    import shutil
    shutil.copy(hero, OUT / "photo-hero.jpg")

print("saved", len(saved))
